function LocalitiesRoadsSings() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };


    const transformDataForTable = (data) => {
        if (!Array.isArray(data) || data.length === 0) 
        {
            return [];
        }

        return data.map(
            (item, index) => (
                {
                    id: index + 1,
                    ...item
                }
            )
        );
    };

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.get('/localities');

            if (response.status === 200) 
            {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } 
        catch (err) 
        {
            console.log(err);
        } 
        finally 
        {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    const transformedData = transformDataForTable(tableData);

    return(
        <h1>Дорожыне знаки в населенных пунктах</h1>
    );
}

export default LocalitiesRoadsSings;
